content.query:
let repoFilter = "{RepoFilter}";
AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_completed"
| where repoFilter == "*" or tostring(Properties.repo_name) == repoFilter
| summarize total_scans = sum(ItemCount)

let repoFilter = "{RepoFilter}";
AppEvents
| where TimeGenerated {TimeRange}
| where Name == "report_created"
| where repoFilter == "*" or tostring(Properties.repo_name) == repoFilter
| summarize total_reports = sum(ItemCount)

let repoFilter = "{RepoFilter}";
AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_completed"
| where repoFilter == "*" or tostring(Properties.repo_name) == repoFilter
| make-series scans = sum(ItemCount) default = 0 on TimeGenerated from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain}

let repoFilter = "{RepoFilter}";
let scans = AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_completed"
| extend repo_name = tostring(Properties.repo_name)
| where repoFilter == "*" or repo_name == repoFilter
| project scan_key = tostring(Properties.scan_key), scan_time = TimeGenerated, repo_name, score = todouble(Measurements.score), verdict = tostring(Properties.verdict);
let reports = AppEvents
| where TimeGenerated {TimeRange}
| where Name == "report_created"
| extend repo_name = tostring(Properties.repo_name)
| where repoFilter == "*" or repo_name == repoFilter
| project scan_key = tostring(Properties.scan_key), report_time = TimeGenerated, report_id = tostring(Properties.report_id);
scans
| join kind=leftouter reports on scan_key
| order by scan_time desc
